import requestsimport json# NYC Open Data sourcesSOURCES = {    "Legislation": "https://data.cityofnewyork.us/resource/uf8p-ervp.json?$limit=500",    "Mayor’s Management Report": "https://data.cityofnewyork.us/resource/qgea-i56i.json?$limit=500",    "Budget Data Explorer": "https://data.cityofnewyork.us/resource/uedp-fegm.json?$limit=500"}# Map bill numbers / indicators to app categories (example mapping)CATEGORY_MAP = {    "Int 1787-2017": "Housing",    "Int 1707-2017": "Transportation",    "Int 1489-2017": "Criminal Justice",    "Int 1472-2017": "Education",    "Int 1447-2017": "Civil Rights & Social Services",    # add more mappings here...}# Helper function: pick first available fielddef pick(item, *fields, default="N/A"):    for f in fields:        if f in item and item[f]:            return str(item[f])    return default# Normalize datedef normalize_date(date_str):    try:        return date_str[:10]    except:        return "2024-01-01"# Fetch all policiesdef fetch_data():    all_policies = []    for source_name, url in SOURCES.items():        print(f"Fetching {source_name} data from: {url}")        try:            res = requests.get(url, timeout=30)            res.raise_for_status()            data = res.json()        except Exception as e:            print(f"Failed {source_name}: {e}")            continue        print(f" → got {len(data)} records")        for item in data:            title = pick(                item,                "title", "name", "bill_title", "measure_name",                "indicator_name", "introduction_title", default="Untitled Policy"            )            description = pick(                item,                "description", "details", "summary", "goal_name",                "measure_description", "full_text", default="No description available."            )            date = normalize_date(pick(                item,                "date", "year", "rpt_dt", "introduction_date", "effective_date",                default="2024-01-01"            ))            # Map category from bill numbers if possible            category = CATEGORY_MAP.get(title, pick(                item, "agency_name", "agency", "category", "department", "division",                default="Uncategorized"            ))            all_policies.append({                "title": title.strip(),                "description": description.strip(),                "date": date,                "category": category.strip(),                "source": source_name            })    return all_policies# Filter by year & categorydef filter_policies(policies, start_year, end_year, category_filter=None):    filtered = []    for p in policies:        try:            year = int(p["date"][:4])            if start_year <= year <= end_year:                if category_filter:                    if category_filter.lower() in p["category"].lower():                        filtered.append(p)                else:                    filtered.append(p)        except:            continue    return filteredif __name__ == "__main__":    print("Welcome to NYC Policy Fetcher!\n")    try:        start_year = int(input("Enter start year (e.g. 2023): "))        end_year = int(input("Enter end year (e.g. 2025): "))    except ValueError:        print("⚠️ Invalid input — defaulting to 2023–2025")        start_year, end_year = 2023, 2025    category_filter = input("Enter category filter (or press Enter for all): ").strip()    # Fetch & filter    all_policies = fetch_data()    filtered = filter_policies(all_policies, start_year, end_year, category_filter)    print(f"\n Found {len(filtered)} matching policies ({start_year}–{end_year})")    # Save JSON    with open("policies.json", "w") as f:        json.dump(filtered, f, indent=2)    print(" Saved to policies.json")    # Show sample    print("\n--- SAMPLE RESULTS ---")    for i, p in enumerate(filtered[:5]):        print(f"{i+1}. {p['title']} | {p['date']} | {p['category']}")        print(f"   {p['description'][:100]}...\n")